  loadGeoJson() {
    return __async(this, null, function* () {
      if (this.continentPaths.length > 0)
        return;
      try {
        const res = yield fetch("/world.geojson?v=" + Date.now());
        const data = yield res.json();
        const paths = [new Path2D(), new Path2D(), new Path2D(), new Path2D()];
        const project = (lng, lat) => {
          const x = (lng + 180) * (1200 / 360);
          const y = (90 - lat) * (800 / 180);
          return [x, y];
        };
        data.features.forEach((feature) => {
          const drawRing = (ring, p) => {
            for (let i = 0; i < ring.length; i++) {
              const [px, py] = project(ring[i][0], ring[i][1]);
              if (i === 0)
                p.moveTo(px, py);
              else
                p.lineTo(px, py);
            }
            p.closePath();
          };
          const coords = feature.geometry.type === "Polygon" ? feature.geometry.coordinates[0][0] : feature.geometry.coordinates[0][0][0];
          const lng = coords[0];
          const lat = coords[1];
          let idx = 1;
          if (lng < -30) {
            idx = lat > 15 ? 0 : 2;
          } else if (lng < 55 && lat < 38) {
            idx = 3;
          }
          const path = paths[idx];
          if (feature.geometry.type === "Polygon") {
            feature.geometry.coordinates.forEach((ring) => drawRing(ring, path));
          } else if (feature.geometry.type === "MultiPolygon") {
            feature.geometry.coordinates.forEach((polygon) => {
              polygon.forEach((ring) => drawRing(ring, path));
            });
          }
        });
        this.continentPaths = paths;
      } catch (e) {
        console.warn("Could not load world map geojson", e);
      }
    });
  }
  syncSignals() {
    if (!this.state)
      return;
    const freshCities = this.state.cities.map((c) => __spreadProps(__spreadValues({}, c), {
      activeSkills: [...c.activeSkills],
      statusEffects: [...c.statusEffects],
      buildings: [...c.buildings]
    }));
    this.cities.set(freshCities);
    this.gamePhase.set(this.state.phase);
    this.turnNumber.set(this.state.turnNumber);
    this.winner.set(this.state.winner);
  }
